def get_letter_data_for_word(word, viewbox_height=41.5):
    """Letter path layout: spaces (ASCII 0x20) horizontal advance without a morph glyph."""
    letters = []
    x_offset = 0
    seen_counts = {}

    for char in word:
        # Plain space separates words visually; glyph count / letter_colors index unchanged for non-path chars.
        if char == ' ':
            x_offset += SPACE_ADVANCE
            continue
        if char not in LETTER_PATHS:
            continue

        data = LETTER_PATHS[char]
        lower = char.lower()
        seen_counts[lower] = seen_counts.get(lower, 0) + 1
        if seen_counts[lower] > 1:
            letter_id = f"{lower}{seen_counts[lower]}"
        else:
            letter_id = lower

        # Build compound path: outer subpath + counter subpath (or zero-area point).
        # fill-rule="evenodd" on the rendered path makes the counter a true transparent hole.
        if data['has_counter']:
            counter_subpath = data['counter_path']
        else:
            center_x = data['width'] / 2
            center_y = viewbox_height / 2
            counter_subpath = normalize_counter_path(data['counter_path'], center_x, center_y)

        compound_path = data['outer_path'] + ' ' + counter_subpath

        letters.append({
            'char': char,
            'id': letter_id,
            'x': x_offset,
            'width': data['width'],
            'compound_path': compound_path,
        })
        x_offset += data['width'] + LETTER_GAP

    # Remove trailing gap from total width
    total_width = x_offset - LETTER_GAP if letters else 0

    if not letters:
        return None

    return {
        'letters': letters,
        'viewbox_height': viewbox_height,
        'total_width': total_width,
        'word': word,
    }


def get_absolute_path(path, x_offset):
    """Convert local path coordinates to absolute by adding x_offset to all X coordinates."""
    import re
    parts = path.split()
    result = []
    is_x = True
    for part in parts:
        if re.match(r'^-?\d+\.?\d*$', part):
            if is_x:
                value = float(part) + x_offset
                # Format with dot decimal separator, then ensure dot is used
                formatted = f"{value:.3f}".replace(',', '.')
                result.append(formatted)
            else:
                result.append(part)
            is_x = not is_x
        else:
            result.append(part)
            is_x = True
    return ' '.join(result)


def build_morph_attributes(letters):
    """Build morph attribute strings for compound paths."""
    if not letters:
        return {}

    letter_ids = [letter["id"] for letter in letters]
    num_letters = len(letter_ids)

    if num_letters == 1:
        morph_to = f"#target-{letter_ids[0]}"
        ghost_leave = f"#ghost-{letter_ids[0]}"
    else:
        target_ids = [f"#target-{lid}" for lid in letter_ids]
        morph_to = ",".join(target_ids[1:] + [target_ids[0]])
        ghost_leave = ",".join([f"#ghost-{lid}" for lid in letter_ids])

    return {
        'morph_to': morph_to,
        'ghost_leave': ghost_leave,
    }


def normalize_counter_path(counter_path, center_x, center_y):
    """Convert a counter path to a single point for letters without real counters.
    This makes the counter effectively invisible (0 area) while maintaining
    the same number of points for KUTE.js morphing compatibility."""
    import re
    
    # Extract all coordinate pairs from the path
    coords = re.findall(r'([ML])\s+([-\d.]+)\s+([-\d.]+)', counter_path)
    
    if not coords:
        return counter_path
    
    # Build new path with all points at the same location
    parts = []
    for i, (cmd, _, _) in enumerate(coords):
        if i == 0:
            parts.append(f"M {center_x:.3f} {center_y:.3f}")
        else:
            parts.append(f"L {center_x:.3f} {center_y:.3f}")
    
    parts.append("Z")
    return " ".join(parts)
